@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500&family=Space+Grotesk:wght@500&display=swap');
@import './tokens.css';

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: var(--background);
  color: var(--on-surface);
  font-family: var(--font-body);
  font-size: 14px;
  line-height: 1.5;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

a { color: var(--primary); text-decoration: none; transition: opacity 0.2s; }
a:hover { opacity: 0.8; text-decoration: none; }

.app-layout {
  display: flex;
  min-height: 100vh;
}

.sidebar {
  width: 240px;
  border-right: 1px solid var(--outline);
  display: flex;
  flex-direction: column;
  position: sticky;
  top: 0;
  height: 100vh;
  background: var(--background);
  flex-shrink: 0;
}

.sidebar-header {
  height: 56px;
  padding: 0 16px;
  display: flex;
  align-items: center;
  gap: 12px;
  border-bottom: 1px solid var(--outline);
}

.sidebar-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px 0;
}

.sidebar-section {
  margin-bottom: 24px;
}

.sidebar-section-title {
  padding: 0 16px;
  font-size: 11px;
  font-weight: 600;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 8px;
}

.sidebar-nav {
  display: flex;
  flex-direction: column;
}

.sidebar-nav-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 16px;
  color: var(--on-surface);
  font-size: 13px;
  font-weight: 500;
  transition: background 0.2s;
}

.sidebar-nav-item:hover {
  background: var(--surface-dim);
  opacity: 1;
}

.sidebar-nav-item.active {
  background: var(--surface-container);
  color: var(--primary);
}

.sidebar-nav-item svg {
  color: var(--on-surface-variant);
}

.sidebar-nav-item.active svg {
  color: var(--primary);
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.header {
  border-bottom: 1px solid var(--outline);
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 56px;
  position: sticky;
  top: 0;
  background: var(--background);
  z-index: 10;
}

.container { width: 100%; max-width: 1400px; margin: 0 auto; padding: 32px 48px; }


.page-title {
  font-family: var(--font-headline);
  font-size: 24px;
  font-weight: 500;
  letter-spacing: -0.02em;
  margin-bottom: 32px;
  color: var(--on-surface);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
  margin-bottom: 40px;
}
.stat-card {
  background: var(--surface-container);
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  padding: 24px;
}
.stat-label {
  font-size: 11px;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
  font-family: var(--font-headline);
}
.stat-value {
  font-size: 32px;
  font-weight: 500;
  color: var(--on-surface);
  line-height: 1;
  font-family: var(--font-headline);
  letter-spacing: -0.02em;
}
.stat-sub {
  font-size: 12px;
  color: var(--on-surface-variant);
  margin-top: 8px;
}

.charts-grid {
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: 16px;
  margin-bottom: 40px;
}
@media (max-width: 768px) { .charts-grid { grid-template-columns: 1fr; } }
.chart-card {
  background: var(--surface);
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  padding: 24px;
}
.chart-title {
  font-size: 11px;
  font-weight: 500;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 24px;
  font-family: var(--font-headline);
}
canvas { max-height: 240px; }

.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}
.section-title {
  font-family: var(--font-headline);
  font-size: 16px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.section-link { font-size: 12px; color: var(--primary); font-weight: 500; }

.table-wrap {
  border: 1px solid var(--outline);
  border-radius: var(--radius);
  overflow: hidden;
}
table { width: 100%; border-collapse: collapse; }
thead th {
  padding: 12px 16px;
  text-align: left;
  font-size: 11px;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  border-bottom: 1px solid var(--outline);
  background: var(--surface-dim);
  font-family: var(--font-headline);
}
tbody td {
  padding: 14px 16px;
  border-bottom: 1px solid var(--outline);
  vertical-align: middle;
}
tbody tr:last-child td { border-bottom: none; }
tbody tr:hover td { background: var(--surface-dim); }

.btn-icon {
  background: transparent;
  border: none;
  color: var(--on-surface-variant);
  cursor: pointer;
  padding: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
}
.btn-icon:hover {
  background: var(--surface-dim);
  color: var(--on-surface);
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 6px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 500;
  line-height: 1;
  background: var(--surface-container);
  color: var(--on-surface-variant);
  border: 1px solid var(--outline);
}

.badge-primary { background: rgba(59, 130, 246, 0.1); color: var(--primary); border-color: rgba(59, 130, 246, 0.2); }
.badge-secondary { background: rgba(245, 158, 11, 0.1); color: #F59E0B; border-color: rgba(245, 158, 11, 0.2); }

.session-group {
  margin-bottom: 32px;
}

.session-group-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--on-surface);
  margin-bottom: 12px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.session-list {
  display: flex;
  flex-direction: column;
  border-top: 1px solid var(--outline);
}

.session-item {
  display: grid;
  grid-template-columns: 40px 1fr auto;
  align-items: center;
  gap: 16px;
  padding: 12px 0;
  border-bottom: 1px solid var(--outline);
  transition: background 0.2s;
}

.session-item:hover {
  background: var(--surface-dim);
}

.avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--surface-container);
  border: 1px solid var(--outline);
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.session-summary {
  font-size: 14px;
  color: var(--on-surface);
  line-height: 1.4;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.session-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--on-surface-variant);
}

