import React, { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Link, useParams } from "react-router-dom";
import { 
  User, 
  Bot, 
  Settings, 
  Clock, 
  Calendar, 
  Database, 
  ChevronDown, 
  ChevronUp,
