  font-size: 14px;
  color: var(--on-surface);
  line-height: 1.4;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.session-header {
  margin-bottom: 48px;
}

.session-title {
  font-size: 24px;
  font-weight: 600;
  color: var(--on-surface);
  line-height: 1.3;
  margin-bottom: 16px;
  letter-spacing: -0.01em;
}

.session-metadata-bar {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
  padding-bottom: 24px;
  border-bottom: 1px solid var(--outline);
}

.meta-item {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: var(--on-surface-variant);
}

.session-detail-layout {
  display: grid;
  grid-template-columns: 1fr 280px;
  gap: 48px;
}

.timeline {
  display: flex;
  flex-direction: column;
  gap: 32px;
  position: relative;
}

.timeline::before {
  content: "";
  position: absolute;
  left: 16px;
  top: 0;
  bottom: 0;
  width: 1px;
  background: var(--outline);
  z-index: 0;
}

.timeline-item {
  display: flex;
  gap: 24px;
  position: relative;
  z-index: 1;
}

.timeline-dot {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--background);
  border: 1px solid var(--outline);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.timeline-content {
  flex: 1;
  min-width: 0;
}

.message-card {
  background: var(--surface);
  border: 1px solid var(--outline);
  border-radius: 8px;
  padding: 16px;
}

.message-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
  font-size: 12px;
  color: var(--on-surface-variant);
}

.message-text {
  font-size: 14px;
  line-height: 1.6;
  color: var(--on-surface);
  white-space: pre-wrap;
}

.tool-call {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 12px;
}

.tool-call-header {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  font-weight: 500;
  color: var(--on-surface);
  cursor: pointer;
}

.tool-call-content {
  background: var(--surface-dim);
  border: 1px solid var(--outline);
  border-radius: 4px;
  padding: 12px;
  font-family: var(--font-mono);
  font-size: 12px;
  overflow-x: auto;
}

.detail-sidebar-section {
  margin-bottom: 32px;
}

.detail-sidebar-title {
  font-size: 11px;
  font-weight: 600;
  color: var(--on-surface-variant);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
}

.filter-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.filter-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 13px;
  color: var(--on-surface);
}

.filter-item input {
  width: 14px;
  height: 14px;
}
